const body = $input.first().json.body || {};

const callbackUrl = body.callback_url || body.webhookUrl;
const requiredFields = ['path', 'clitype'];
const missingFields = requiredFields.filter((field) => !body[field]);

if (!callbackUrl) {
  missingFields.push('callback_url');
}

if (missingFields.length > 0) {
  throw new Error(`Missing required fields: ${missingFields.join(', ')}`);
}

const attachments = Array.isArray(body.attachments) ? body.attachments : [];
const prompt = typeof body.prompt === 'string' ? body.prompt.trim() : '';

if (prompt.length === 0 && attachments.length === 0) {
  throw new Error('Prompt or attachments required');
}

if (prompt.length > 5000) {
  throw new Error('Prompt too long. Maximum 5000 characters');
}

const clitype = String(body.clitype).toLowerCase().trim();
const validCliTypes = ['gemini', 'claude', 'codex'];
if (!validCliTypes.includes(clitype)) {
  throw new Error(`Invalid clitype. Must be one of: ${validCliTypes.join(', ')}`);
}

const path = String(body.path).trim();
if (!path.startsWith('/') || path.includes('..') || path.includes('~') || /[\r\n]/.test(path)) {
  throw new Error('Invalid path. Must be an absolute path without .., ~, or newlines');
}

const callbackUrlMatch = String(callbackUrl).trim().match(/^(https?):\/\/([^\/?#:]+)(:\d+)?(\/.*)?$/i);
if (!callbackUrlMatch) {
  throw new Error('Invalid callback_url format');
}
const callbackProtocol = `${callbackUrlMatch[1].toLowerCase()}:`;
const host = callbackUrlMatch[2].toLowerCase();

if (!['http:', 'https:'].includes(callbackProtocol)) {
  throw new Error('callback_url must use http or https');
}

const forbiddenHostPatterns = [
  /^localhost$/,
  /^127\./,
  /^10\./,
  /^192\.168\./,
  /^169\.254\./,
  /^172\.(1[6-9]|2\d|3[0-1])\./,
  /^0\.0\.0\.0$/,
  /^::1$/,
  /^fe80:/,
  /^fc/i,
  /^fd/i,
];
if (forbiddenHostPatterns.some((pattern) => pattern.test(host))) {
  throw new Error('Forbidden callback_url host');
}

const maxAttachments = 10;
const maxEncodedBytesPerAttachment = 10 * 1024 * 1024;
const maxApproxDecodedBytesTotal = 25 * 1024 * 1024;
if (attachments.length > maxAttachments) {
  throw new Error(`Too many attachments. Maximum ${maxAttachments}`);
}

let approxDecodedBytesTotal = 0;
for (const [index, attachment] of attachments.entries()) {
  if (!attachment || typeof attachment !== 'object') {
    throw new Error(`Attachment ${index + 1} is invalid`);
  }

  const fileName = typeof attachment.file_name === 'string' ? attachment.file_name.trim() : '';
  const data = typeof attachment.data === 'string' ? attachment.data.trim() : '';

  if (!fileName) {
    throw new Error(`Attachment ${index + 1} is missing file_name`);
  }

  if (!data) {
    throw new Error(`Attachment ${index + 1} is missing data`);
  }

  if (data.length > maxEncodedBytesPerAttachment) {
    throw new Error(`Attachment ${fileName} exceeds the maximum allowed size`);
  }

  const sanitizedFileName = fileName.replace(/[^a-zA-Z0-9._-]/g, '_').replace(/^_+|_+$/g, '');
  if (!sanitizedFileName) {
    throw new Error(`Attachment ${index + 1} has an invalid file_name`);
  }

  approxDecodedBytesTotal += Math.floor((data.length * 3) / 4);
}

if (approxDecodedBytesTotal > maxApproxDecodedBytesTotal) {
  throw new Error('Attachments exceed the maximum total size');
}

const hasVoiceNote = attachments.some((attachment) => {
  const mimeType = typeof attachment.mime_type === 'string' ? attachment.mime_type : '';
  return mimeType.startsWith('audio/');
}) || body.has_voice_note === true;

const isResume = body.is_resume === true;
let sessionId = null;
if (isResume) {
  sessionId = body['session-id'] || body.session_id;
  if (!sessionId || typeof sessionId !== 'string') {
    throw new Error('session_id required when is_resume is true');
  }
  sessionId = sessionId.trim();
  if (!sessionId || /[\r\n]/.test(sessionId)) {
    throw new Error('Invalid session_id');
  }
}

let model = null;
if (body.model !== undefined && body.model !== null && String(body.model).trim() !== '') {
  model = String(body.model).trim();
  if (!/^[a-zA-Z0-9._:-]+$/.test(model)) {
    throw new Error('Invalid model value');
  }
}

return {
  path,
  prompt,
  clitype,
  callback_url: String(callbackUrl).trim(),
  is_resume: isResume,
  has_voice_note: hasVoiceNote,
  session_id: sessionId,
  attachments,
  model,
  workflow_id: $input.first().json.headers['x-workflow-id'] || 'unknown',
};

const data = $input.first().json;
const attachments = Array.isArray(data.attachments) ? data.attachments : [];
const hasAttachments = attachments.length > 0;

const shellEscape = (value) => `'${String(value).replace(/'/g, `'\\''`)}'`;

const safePath = shellEscape(data.path);
const safePromptPath = shellEscape(`${data.attachment_dir}/prompt.txt`);
const safeAttachmentDir = shellEscape(data.attachment_dir);
const workspaceFlag = hasAttachments ? `--include-directories ${safeAttachmentDir} ` : '';
const modelFlag = data.model ? `--model ${shellEscape(data.model)} ` : '';
const resumeFlag = data.is_resume && data.session_id ? `--resume ${shellEscape(data.session_id)} ` : '';

const command = [
  `cd ${safePath}`,
  `PROMPT=$(cat ${safePromptPath})`,
  `timeout 1800 gemini --yolo ${workspaceFlag}${modelFlag}${resumeFlag}-p "$PROMPT" --output-format json 2>&1`,
].join(' && ');

return {
  command,
  cleanup_command: data.cleanup_command || 'true',
  clitype: 'gemini',
  callback_url: data.callback_url,
  workflow_id: data.workflow_id,
};

const data = $input.first().json;

const shellEscape = (value) => `'${String(value).replace(/'/g, `'\\''`)}'`;

const safePath = shellEscape(data.path);
const safePromptPath = shellEscape(`${data.attachment_dir}/prompt.txt`);
const resumeFlag = data.is_resume && data.session_id ? `--resume ${shellEscape(data.session_id)} ` : '';

const command = [
  `cd ${safePath}`,
  `PROMPT=$(cat ${safePromptPath})`,
  `timeout 1800 claude ${resumeFlag}-p "$PROMPT" --output-format json 2>&1`,
].join(' && ');

return {
  command,
  cleanup_command: data.cleanup_command || 'true',
  clitype: 'claude',
  callback_url: data.callback_url,
  workflow_id: data.workflow_id,
};

const item = $input.first();
const metadata = $("Wait for Uploads").first().json;
const clitype = item.json.clitype || metadata.clitype;
const workflowId = item.json.workflow_id || metadata.workflow_id;
const callbackUrl = item.json.callback_url || metadata.callback_url;

if (item.json.error) {
  return {
    success: false,
    error: item.json.error,
    error_type: 'ssh_error',
    clitype,
    workflow_id: workflowId,
    callback_url: callbackUrl,
  };
}

const stdout = item.json.stdout || '';
const stderr = item.json.stderr || '';
const combinedOutput = [stdout, stderr].filter(Boolean).join('\n');
const exitCode = typeof item.json.exitCode === 'number' ? item.json.exitCode : null;

if (!combinedOutput.trim()) {
  return {
    success: false,
    error: 'No output received from CLI',
    error_type: 'empty_output',
    clitype,
    workflow_id: workflowId,
    callback_url: callbackUrl,
  };
}

if (/\btimeout\b/i.test(combinedOutput)) {
  return {
    success: false,
    error: 'Command execution timed out after 1800 seconds',
    error_type: 'timeout',
    raw_output: combinedOutput.slice(-4000),
    clitype,
    workflow_id: workflowId,
    callback_url: callbackUrl,
  };
}

function parseCodexJsonl(text) {
  const lines = text.split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
  const events = [];
  for (const line of lines) {
    if (!line.startsWith('{')) continue;
    try {
      events.push(JSON.parse(line));
    } catch (error) {}
  }

  if (events.length === 0) {
    return null;
  }

  const threadStarted = events.find((event) => event.type === 'thread.started');
  const completedMessages = events.filter((event) => event.type === 'item.completed' && event.item && event.item.type === 'agent_message');
  const lastMessage = completedMessages.length > 0 ? completedMessages[completedMessages.length - 1] : null;

  return {
    session_id: threadStarted?.thread_id || null,
    response: lastMessage?.item?.text || '',
    stats: events.find((event) => event.type === 'turn.completed')?.usage || null,
  };
}

function extractJson(text) {
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start === -1 || end === -1 || end < start) {
    return null;
  }

  const candidate = text.slice(start, end + 1);
  try {
    return JSON.parse(candidate);
  } catch (error) {
    const balancedMatches = text.match(/\{(?:[^{}]|(\{(?:[^{}]|(\{[^{}]*\}))*\}))*\}/g);
    if (!balancedMatches) {
      return null;
    }

    for (let index = balancedMatches.length - 1; index >= 0; index -= 1) {
      try {
        return JSON.parse(balancedMatches[index]);
      } catch (innerError) {}
    }

    return null;
  }
}

try {
  let data;
  if (clitype === 'codex') {
    data = parseCodexJsonl(combinedOutput);
    if (!data) {
      if (exitCode !== null && exitCode !== 0) {
        return {
          success: false,
          error: `Codex exited with code ${exitCode}`,
          error_type: 'execution_error',
          raw_output: combinedOutput.slice(-10000),
          clitype,
          workflow_id: workflowId,
          callback_url: callbackUrl,
        };
      }
      throw new Error('No valid Codex JSONL events found in output');
    }
  } else {
    data = extractJson(combinedOutput);
    if (!data) {
      if (exitCode !== null && exitCode !== 0) {
        return {
          success: false,
          error: `CLI exited with code ${exitCode}`,
          error_type: 'execution_error',
          raw_output: combinedOutput.slice(-10000),
          clitype,
          workflow_id: workflowId,
          callback_url: callbackUrl,
        };
      }

      throw new Error('No valid JSON found in output');
    }
  }

  let response = data.response;
  if (typeof response === 'string') {
    const trimmed = response.trim();
    if (trimmed.startsWith('{') || trimmed.startsWith('[')) {
      try {
        const innerData = JSON.parse(trimmed);
        response = innerData.response || innerData;
      } catch (error) {}
    }
  }

  return {
    success: true,
    session_id: data.session_id || metadata.session_id || null,
    response,
    stats: data.stats || null,
    clitype,
    workflow_id: workflowId,
    callback_url: callbackUrl,
  };
} catch (error) {
  return {
    success: false,
    error: `Failed to parse CLI output: ${error.message}`,
    error_type: 'parse_error',
    raw_output: combinedOutput.slice(-10000),
    clitype,
    workflow_id: workflowId,
    callback_url: callbackUrl,
  };
}

// Log callback result
const item = $input.first();

if (item.json.error) {
  console.log('Callback failed:', item.json.error);
  return {
    callback_status: 'failed',
    callback_error: item.json.error
  };
}

return {
  callback_status: 'success',
  callback_response_code: item.json.statusCode
};

const input = $input.first().json;
const attachments = Array.isArray(input.attachments) ? input.attachments : [];

const shellEscape = (value) => `'${String(value).replace(/'/g, `'\\''`)}'`;
const normalizeName = (value) => value.replace(/[^a-zA-Z0-9._-]/g, '_').replace(/^_+|_+$/g, '') || 'attachment';

const sessionTokenSource = input.session_id || Math.random().toString(36).slice(2);
const sessionToken = normalizeName(String(sessionTokenSource));
const tempDir = `/tmp/code-cli/${sessionToken}`;

let attachmentNote = '';
if (attachments.length > 0) {
  attachmentNote = '\n\nAttached files available in workspace:';
}

attachments.forEach((attachment) => {
  attachmentNote += `\n- ${normalizeName(String(attachment.file_name || 'attachment'))}`;
});

let finalPrompt = input.prompt || '';
if (input.has_voice_note === true) {
  finalPrompt = `[VOICE NOTE ATTACHED] Please listen to the attached voice note and respond accordingly. ${finalPrompt}`.trim();
}

const promptFileContent = `${finalPrompt}${attachmentNote}`.trim();
const setupDelimiter = 'PROMPT_EOF_CODE_CLI';
const items = [{
  ...input,
  upload_command: `mkdir -p ${shellEscape(tempDir)} && cat <<'${setupDelimiter}' > ${shellEscape(`${tempDir}/prompt.txt`)}\n${promptFileContent}\n${setupDelimiter}`,
  is_setup: true,
  attachment_note: attachmentNote,
  attachment_dir: tempDir,
  cleanup_command: `rm -rf ${shellEscape(tempDir)}`,
}];

attachments.forEach((attachment, index) => {
  const safeFileName = normalizeName(String(attachment.file_name || `attachment-${index + 1}`));
  const filePath = `${tempDir}/${safeFileName}`;
  const delimiter = `FILE_EOF_${index}`;

  items.push({
    ...input,
    upload_command: `base64 -d <<'${delimiter}' > ${shellEscape(filePath)}\n${String(attachment.data || '').trim()}\n${delimiter}`,
    is_file: true,
    file_name: safeFileName,
    attachment_dir: tempDir,
    cleanup_command: `rm -rf ${shellEscape(tempDir)}`,
  });
});

return items;

const originalItems = $("Handle Attachments").all();
const uploadResults = $input.all();
const setupItem = originalItems.find((item) => item.json.is_setup) || originalItems[0];

if (!setupItem) {
  throw new Error('Attachment setup metadata is missing');
}

if (uploadResults.length !== originalItems.length) {
  throw new Error(`Expected ${originalItems.length} upload results but received ${uploadResults.length}`);
}

const failedUpload = uploadResults.find((item) => {
  if (item.json.error) {
    return true;
  }
  if (typeof item.json.exitCode === 'number' && item.json.exitCode !== 0) {
    return true;
  }
  return false;
});

if (failedUpload) {
  const reason = failedUpload.json.error || failedUpload.json.stderr || `Upload exited with code ${failedUpload.json.exitCode}`;
  throw new Error(`Attachment upload failed: ${reason}`);
}

return {
  ...setupItem.json,
  uploaded_item_count: uploadResults.length,
};

const data = $input.first().json;

const shellEscape = (value) => `'${String(value).replace(/'/g, `'\\''`)}'`;

const safePath = shellEscape(data.path);
const safePromptPath = shellEscape(`${data.attachment_dir}/prompt.txt`);
const modelFlag = data.model ? ` -m ${shellEscape(data.model)}` : '';

let codexInvocation;
if (data.is_resume && data.session_id) {
  codexInvocation = `timeout 1800 codex exec resume --json --skip-git-repo-check${modelFlag} ${shellEscape(data.session_id)} \"$PROMPT\"`;
} else {
  codexInvocation = `timeout 1800 codex exec --json --skip-git-repo-check -C .${modelFlag} \"$PROMPT\"`;
}

const command = [
  `cd ${safePath}`,
  `PROMPT=$(cat ${safePromptPath})`,
  `${codexInvocation} 2>&1`,
].join(' && ');

return {
  command,
  cleanup_command: data.cleanup_command || 'true',
  clitype: 'codex',
  callback_url: data.callback_url,
  workflow_id: data.workflow_id,
};
